# FitNexus Coach BlackGold - Landing Page V11
# Ajusta textos que pareciam promessa falsa ou irrelevantes para usuario final.
# Run:
# powershell -ExecutionPolicy Bypass -File "E:\FitNexus_Coach_BlackGold\aplicar_landing_page_v11.ps1"

$ErrorActionPreference = "Stop"

$AppRoot = "E:\FitNexus_Coach_BlackGold\03_app_flutter\fitnexus_app"
$LandingFile = Join-Path $AppRoot "lib\features\landing\landing_page.dart"
$BackupRoot = "E:\FitNexus_Coach_BlackGold\17_backups\landing_page"
$Timestamp = Get-Date -Format "yyyyMMdd_HHmmss"

Write-Host ""
Write-Host "FitNexus Coach BlackGold - Aplicando landing_page.dart V11" -ForegroundColor Yellow
Write-Host "App root: $AppRoot" -ForegroundColor Cyan
Write-Host ""

if (!(Test-Path $AppRoot)) {
    Write-Host "ERRO: pasta do app Flutter nao encontrada." -ForegroundColor Red
    Write-Host $AppRoot -ForegroundColor Red
    Pause
    exit 1
}

if (!(Test-Path $LandingFile)) {
    Write-Host "ERRO: landing_page.dart nao encontrado." -ForegroundColor Red
    Write-Host $LandingFile -ForegroundColor Red
    Pause
    exit 1
}

New-Item -ItemType Directory -Force -Path $BackupRoot | Out-Null
Copy-Item $LandingFile (Join-Path $BackupRoot "landing_page_before_v11_$Timestamp.dart.bak") -Force

$Base64Content = ""
$Bytes = [System.Convert]::FromBase64String($Base64Content)
$Text = [System.Text.Encoding]::UTF8.GetString($Bytes)
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($LandingFile, $Text, $Utf8NoBom)

Set-Location $AppRoot

Write-Host ""
Write-Host "Arquivo V11 aplicado com sucesso." -ForegroundColor Green
Write-Host "Backup salvo em:" -ForegroundColor Cyan
Write-Host $BackupRoot
Write-Host ""
Write-Host "Agora rode:" -ForegroundColor Cyan
Write-Host "flutter analyze"
Write-Host "flutter run -d chrome"
Write-Host ""
Pause
